class Solution:
    def discountPrices(self, sentence: str, discount: int) -> str:
        words = sentence.split()
        result = []
        for word in words:
            if word.startswith("$"):
                price = float(word[1:])
                discounted_price = price * (1 - discount / 100)
                result.append(f"${discounted_price:.2f}")
            else:
                result.append(word)
        return " ".join(result)
